CREATE TABLE Pilot ( PilotID INTEGER PRIMARY KEY, LicenseNumber VARCHAR(10) NOT NULL, FirstName VARCHAR(20) NOT NULL, LastName VARCHAR(20) NOT NULL, PhoneNumber VARCHAR(30) NOT NULL, Email VARCHAR(30) NOT NULL, Address VARCHAR(50) NOT NULL );
CREATE TABLE Destination ( DestinationID INTEGER PRIMARY KEY NOT NULL, DestinationCountry VARCHAR(20) NOT NULL, City VARCHAR(20) NOT NULL, Airport VARCHAR(20) NOT NULL, TimeZone VARCHAR(30) NOT NULL );
CREATE TABLE WorkSchedule ( WorkScheduleID INTEGER PRIMARY KEY, PilotID INTEGER NOT NULL, Dayoftheweek VARCHAR(10) NOT NULL, StartTime TIME NOT NULL, EndTime TIME NOT NULL, TotalHours SMALLINT NOT NULL, FOREIGN KEY (PilotID) REFERENCES Pilot(PilotID) );
CREATE TABLE Flight ( FlightID INTEGER PRIMARY KEY, FlightNumber VARCHAR(7) NOT NULL, DepartureTime TIME NOT NULL, DepartureDate DATE NOT NULL, ArrivalTime TIME NOT NULL, ArrivalDate DATE NOT NULL, Capacity SMALLINT NOT NULL, Status VARCHAR(10) CHECK (Status IN ('Scheduled', 'Cancelled', 'Delayed')) NOT NULL, ArrivalDestinationID INTEGER NOT NULL, DepartureDestinationID INTEGER NOT NULL, CaptainID INTEGER, CoPilotID INTEGER, FOREIGN KEY (ArrivalDestinationID) REFERENCES Destination(DestinationID), FOREIGN KEY (DepartureDestinationID) REFERENCES Destination(DestinationID), FOREIGN KEY (CaptainID) REFERENCES Pilot(PilotID), FOREIGN KEY (CoPilotID) REFERENCES Pilot(PilotID) );